INSERT INTO `sliders` (`id`, `category_id`, `title`, `subtitle`, `description`, `file_name`, `is_published`, `created_by`, `updated_by`, `deleted_at`, `created_at`, `updated_at`) VALUES
	(1, 6, 'Welcome To', 'Medirilinix', 'We\'re a company based in New Delhi trying to bring you the latest fashion of the best quality at the lowest possible prices. We had started this company from our bedroom and it\'s now grown to a team of 15+ people working full time and part time contributing their blood.', 'rRHZ73bh7yBDTMXwnHnx.jpg', 1, 1, 1, NULL, '2025-12-07 11:43:00', '2025-12-12 16:59:22'),
	(2, 16, '', '', '', 'xz33bxv09wfvfa6udCsa.jpg', 1, 1, 1, NULL, '2025-12-12 15:25:03', '2025-12-12 17:01:22'),
	(3, 8, 'Aut aut dolores labo', 'Quaerat sint eiusmod', 'Welcome to Pexels! Pexels is a platform that allows you to post, link, store, share and contribute content to the platform. Our goal is to help designers, bloggers and everyone who is looking for content to discover and find high quality.', 'U8mf7LYvqos6S7vWD5za.jpg', 1, 1, 1, NULL, '2025-12-12 15:27:31', '2025-12-12 17:01:29');
